    def execute_where_query(self, js_expression):
        try:
            query = {"$where": js_expression}
            results = list(self.collection.find(query))
            return results
        except Exception as e:
            return {"error": str(e)}
    
    def execute_custom_filter(self, filter_expression):
        try:
            results = list(self.collection.find(filter_expression))
            return results
        except Exception as e:
            return {"error": str(e)}
    
    def execute_aggregation_with_function(self, pipeline):
        try:
            results = list(self.collection.aggregate(pipeline))
            return results
        except Exception as e:
            return {"error": str(e)}
    
    def execute_map_reduce(self, map_function, reduce_function, query=None):
        try:
            from bson.code import Code
            map_func = Code(map_function)
            reduce_func = Code(reduce_function)
            
            result = self.collection.map_reduce(
                map_func,
                reduce_func,
                "map_reduce_results",
                query=query
            )
            
            return list(self.db["map_reduce_results"].find())
        except Exception as e:
            return {"error": str(e)}
    
    def filter_by_salary_range(self, min_salary, max_salary):
        js_expression = f"this.salary >= {min_salary} && this.salary <= {max_salary}"
